customCss:
.mfp.mfp-concert-sticky{--paper:#fffdf8;--ink:#1f2937;--line:#e5e7eb;background:linear-gradient(135deg,#fffaf0,#fdf2f8 40%,#eef6ff);padding:28px;color:var(--ink)}
.mfp-concert-sticky .mfp-shell{max-width:1160px;margin:0 auto;display:grid;grid-template-columns:320px 1fr;gap:24px}
.mfp-concert-sticky .mfp-aside{display:grid;gap:16px;align-content:start}
.mfp-concert-sticky .note{padding:22px;border-radius:22px;box-shadow:0 16px 34px rgba(15,23,42,.10);background:#fff;border:1px solid rgba(15,23,42,.06)}
.mfp-concert-sticky .note span{display:block;font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:#6b7280;margin-bottom:8px}
.mfp-concert-sticky .note strong{display:block;font-size:28px;line-height:1.05;margin-bottom:10px}
.mfp-concert-sticky .note p{margin:0;color:#475569}
.mfp-concert-sticky .note-yellow{background:#fef3c7;transform:rotate(-1deg)}
.mfp-concert-sticky .note-pink{background:#fce7f3;transform:rotate(1.5deg)}
.mfp-concert-sticky .note-blue{background:#dbeafe;transform:rotate(-1.75deg)}
.mfp-concert-sticky .mfp-main{display:grid;gap:18px}
.mfp-concert-sticky .hero-board,.mfp-concert-sticky .board{background:rgba(255,255,255,.86);backdrop-filter:blur(6px);border:1px solid rgba(255,255,255,.72);border-radius:28px;padding:24px;box-shadow:0 24px 52px rgba(15,23,42,.08)}
.mfp-concert-sticky .board-title{font-size:13px;font-weight:800;text-transform:uppercase;letter-spacing:.08em;color:#7c3aed;margin-bottom:14px}
.mfp-concert-sticky .music-grid{display:grid;grid-template-columns:1.15fr .85fr .85fr;gap:14px}
.mfp-concert-sticky .music-card{position:relative;overflow:hidden;border-radius:22px;min-height:220px;background:#fff;box-shadow:0 14px 32px rgba(15,23,42,.08)}
.mfp-concert-sticky .music-card img{width:100%;height:100%;object-fit:cover;display:block}
.mfp-concert-sticky .music-copy{position:absolute;left:14px;right:14px;bottom:14px;padding:12px 14px;border-radius:16px;background:rgba(255,255,255,.90);backdrop-filter:blur(8px)}
.mfp-concert-sticky .music-copy strong{display:block;font-size:16px;line-height:1.1;color:#111827}
.mfp-concert-sticky .music-copy span{display:block;margin-top:4px;font-size:12px;color:#475569}
.mfp-concert-sticky .mfp-actions button[type=submit]{width:100%;border:none;border-radius:20px;padding:16px 28px;background:linear-gradient(135deg,#7c3aed,#ec4899);color:#fff;font-weight:800;font-size:16px;box-shadow:0 16px 32px rgba(236,72,153,.24)}
.mfp-concert-sticky .mfp-footer{padding:2px 4px 0;text-align:center}.mfp-concert-sticky .mfp-footer p{margin:0;color:#475569;font-size:13px}
.mfp-concert-sticky .mf-field,.mfp-concert-sticky .mf-row{margin-bottom:14px}
.mfp-concert-sticky .mf-field-checkbox .mf-options,.mfp-concert-sticky .mf-field-radio .mf-options,.mfp-concert-sticky .mf-checkbox-group,.mfp-concert-sticky .mf-radio-group{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}
.mfp-concert-sticky .mf-field-checkbox .mf-option,.mfp-concert-sticky .mf-field-radio .mf-option,.mfp-concert-sticky .mf-checkbox-option,.mfp-concert-sticky .mf-radio-option{display:flex;align-items:center;gap:10px;padding:12px 14px;border-radius:16px;background:rgba(255,255,255,.9);border:1px solid rgba(124,58,237,.12)}
.mfp-concert-sticky .mf-field-checkbox .mf-option label,.mfp-concert-sticky .mf-field-radio .mf-option label,.mfp-concert-sticky .mf-checkbox-option label,.mfp-concert-sticky .mf-radio-option label{margin:0;font-weight:600;color:#1f2937}
@media(max-width:860px){.mfp.mfp-concert-sticky{padding:18px}.mfp-concert-sticky .mfp-shell{grid-template-columns:1fr}.mfp-concert-sticky .music-grid{grid-template-columns:1fr 1fr}}
@media(max-width:640px){.mfp-concert-sticky .mf-field-checkbox .mf-options,.mfp-concert-sticky .mf-field-radio .mf-options,.mfp-concert-sticky .mf-checkbox-group,.mfp-concert-sticky .mf-radio-group{grid-template-columns:1fr}.mfp-concert-sticky .music-grid{grid-template-columns:1fr}.mfp-concert-sticky .music-card{min-height:200px}}
